35	export interface NormalizedMarketListFilters {
36	  status?: string;
37	  includeResolved?: true;
38	}
39	
40	async function request<T>(
41	  path: string,
42	  options: RequestInit = {},
43	  session?: Session,
44	): Promise<T> {
45	  const headers: Record<string, string> = {
46	    ...(options.headers as Record<string, string>),
47	  };
48	
49	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
50	    headers["Content-Type"] = "application/json";
51	  }
52	
53	  if (session?.agentId) {
54	    headers["X-Bayes-Agent-Id"] = session.agentId;
55	  }
56	
57	  const res = await fetch(`${API_BASE}${path}`, {
58	    ...options,
59	    headers,
60	  });
61	
62	  const body = await res.json();
63	
64	  if (!res.ok) {
65	    const err = body as ApiError;
66	    throw new BayesApiError(
67	      res.status,
68	      err.error?.code ?? "unknown_error",
69	      err.error?.details ?? {},
70	    );
71	  }
72	
73	  return body as T;
74	}
75	
76	export function normalizeMarketListFilters(
77	  filters?: MarketListFilterInput,
78	): NormalizedMarketListFilters {
79	  const status = typeof filters === "string"
80	    ? filters
81	    : filters?.status;
82	  const includeResolved = (
83	    typeof filters !== "string"
84	    && filters?.includeResolved === true
85	  ) || status === "resolved";
86	
87	  return {
88	    ...(status ? { status } : {}),
89	    ...(includeResolved ? { includeResolved: true } : {}),
90	  };
91	}
92	
93	function serializeMarketListFilters(filters?: MarketListFilterInput): string {
94	  const normalizedFilters = normalizeMarketListFilters(filters);
95	  const params = new URLSearchParams();
96	
97	  if (normalizedFilters.status) {
98	    params.set("status", normalizedFilters.status);
99	  }
100	
101	  if (normalizedFilters.includeResolved) {
102	    params.set("include_resolved", "true");
103	  }
104	
105	  const queryString = params.toString();
106	  return queryString ? `?${queryString}` : "";
107	}
108	
109	export function listMarkets(
110	  filters?: MarketListFilterInput,
111	): Promise<MarketListResponse> {
112	  return request<MarketListResponse>(`/v1/markets${serializeMarketListFilters(filters)}`);
113	}
