} from "./types";

const API_BASE = import.meta.env.VITE_API_BASE ?? "";

export class BayesApiError extends Error {
  constructor(
    public status: number,
    public code: string,
    public details: Record<string, unknown> = {},
  ) {
    super(`${code}: ${status}`);
    this.name = "BayesApiError";
  }
}

