      if (effectClosed) {
        return;
      }

      socket = new WebSocket(api.getMarketEventsWebSocketUrl(marketId));

      socket.addEventListener("open", () => {
        const reconnecting = reconnectAttemptRef.current > 0;
        reconnectAttemptRef.current = 0;
